package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.StringReader;

import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    public void testIsQuoteCharacterSet() {
        // Given
        char delimiter = ',';
        char quoteChar = '"';
        CSVFormat csvFormat = null;
        try {
            csvFormat = CSVFormat.class.getDeclaredConstructor(char.class, Character.class, QuoteMode.class, Character.class, Character.class, boolean.class, boolean.class, String.class, String.class, String[].class, boolean.class, boolean.class)
                    .newInstance(delimiter, quoteChar, null, null, null, false, true, "\r\n", null, null, false, false);
        } catch (Exception e) {
            e.printStackTrace();
        }

        // When
        boolean result = csvFormat.isQuoteCharacterSet();

        // Then
        assertTrue(result);
    }
}
